SELECT count(*) FROM keyword, movie_keyword, title, movie_companies, cast_info, kind_type, movie_info, role_type WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND movie_companies.movie_id = title.id AND cast_info.movie_id = title.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND cast_info.role_id = role_type.id;